import{_ as t}from"./chunks/文件受限图.DsG20F9s.js";import{_ as i,o as a,c as r,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Modération d’images et mode d’accès","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/Safety/image-moderation-and-access-mode.md","filePath":"fr-FR/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),o={name:"fr-FR/Safety/image-moderation-and-access-mode.md"};function d(l,e,n,c,u,m){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="moderation-d-images-et-mode-d-acces" tabindex="-1">Modération d’images et mode d’accès <a class="header-anchor" href="#moderation-d-images-et-mode-d-acces" aria-label="Permalink to &quot;Modération d’images et mode d’accès&quot;">​</a></h1><p>La modération d’images et le mode d’accès contrôlent les fichiers visibles par les visiteurs selon les règles publiques, les listes et la classification d’âge.</p><p>Ils fonctionnent avec la galerie publique, l’API d’image aléatoire et l’accès externe aux fichiers.</p><h2 id="ce-que-cela-permet" tabindex="-1">Ce que cela permet <a class="header-anchor" href="#ce-que-cela-permet" aria-label="Permalink to &quot;Ce que cela permet&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fonction</th><th>Description</th></tr></thead><tbody><tr><td>Modération d’images</td><td>Enregistrer des informations de contenu ou de classification</td></tr><tr><td>Liste noire</td><td>Exclure des fichiers qui ne doivent pas être publics</td></tr><tr><td>Mode liste blanche</td><td>Publier uniquement les fichiers explicitement autorisés</td></tr><tr><td>Contrôle par âge</td><td>Ajuster la visibilité de R12, R16, R18 et similaires</td></tr><tr><td>Mode d’accès</td><td>Modifier globalement ce que les visiteurs peuvent voir</td></tr></tbody></table><h2 id="mode-d-acces" tabindex="-1">Mode d’accès <a class="header-anchor" href="#mode-d-acces" aria-label="Permalink to &quot;Mode d’accès&quot;">​</a></h2><p>Le mode d’accès limite ce que les pages publiques et l’API aléatoire peuvent renvoyer.</p><p>Si vous voulez un site adapté à tous les publics, configurez le mode pour ne renvoyer que des fichiers généraux. Pour un usage interne ou restreint, ajustez des règles plus souples selon le besoin.</p><h2 id="fichier-restreint" tabindex="-1">Fichier restreint <a class="header-anchor" href="#fichier-restreint" aria-label="Permalink to &quot;Fichier restreint&quot;">​</a></h2><p>Lorsqu’un fichier est restreint, le visiteur voit un message au lieu du contenu original.</p><p><img src="'+t+'" alt="Fichier restreint" loading="lazy"></p><h2 id="modes-d-exploitation" tabindex="-1">Modes d’exploitation <a class="header-anchor" href="#modes-d-exploitation" aria-label="Permalink to &quot;Modes d’exploitation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approche</th><th>Quand l’utiliser</th></tr></thead><tbody><tr><td>Liste noire</td><td>Publier par défaut et exclure les fichiers problématiques</td></tr><tr><td>Liste blanche</td><td>Publier uniquement ce qui a été vérifié et autorisé</td></tr><tr><td>Classification d’âge</td><td>Adapter la visibilité selon le niveau de contenu</td></tr></tbody></table><p>Pour un site public, la liste blanche ou la classification d’âge aident à éviter les publications indésirables.</p><h2 id="points-a-verifier" tabindex="-1">Points à vérifier <a class="header-anchor" href="#points-a-verifier" aria-label="Permalink to &quot;Points à vérifier&quot;">​</a></h2><ol><li>Vérifiez si le fichier apparaît dans la galerie publique.</li><li>Assurez-vous que l’API aléatoire ne renvoie pas de fichiers restreints.</li><li>Après modification des listes, tenez compte du cache ou des résultats déjà générés.</li><li>Si vous utilisez la classification automatique, vérifiez manuellement les fichiers sensibles, car les modèles peuvent se tromper.</li></ol>',16)])])}const b=i(o,[["render",d]]);export{f as __pageData,b as default};
